  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
    // Dead cell (1,1) has 3 live neighbors: (0,0),(1,0),(0,1) -> becomes alive
    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
